import React, { useState, useEffect, useRef } from 'react';
import { BrowserRouter as Router, Routes, Route, useNavigate, useParams } from 'react-router-dom';
import axios from 'axios';
import { motion, AnimatePresence } from 'framer-motion';
import { Github, Download, Twitter, Share2, Activity } from 'lucide-react';
import * as htmlToImage from 'html-to-image';
import Grass3D from './components/Grass3D';
import './index.css';

function MainApp() {
  const [username, setUsername] = useState('');
  const [loading, setLoading] = useState(false);
  const [data, setData] = useState(null);
  const [error, setError] = useState('');

  const navigate = useNavigate();
  const { user } = useParams();
  const cardRef = useRef(null);

  // If URL has user param, load it automatically
  useEffect(() => {
    if (user) {
      setUsername(user);
      fetchData(user);
    }
  }, [user]);

  const fetchData = async (targetUser) => {
    if (!targetUser) return;

    setLoading(true);
    setError('');
    setData(null);

    try {
      const response = await axios.get(`http://localhost:5000/api/analyze/${targetUser}`);
      setData(response.data);
      // Update URL without full reload
      if (user !== targetUser) {
        navigate(`/user/${targetUser}`, { replace: true });
      }
    } catch (err) {
      setError(err.response?.data?.error || 'Failed to fetch data');
    } finally {
      setLoading(false);
    }
  };

  const handleSearch = (e) => {
    e.preventDefault();
    if (username.trim()) {
      fetchData(username.trim());
    }
  };

  const handleDownload = () => {
    if (cardRef.current) {
      const filter = (node) => {
        // Exclude the actions div so buttons aren't on the image
        return !node.classList?.contains('actions');
      };

      htmlToImage.toPng(cardRef.current, { backgroundColor: '#050505', cacheBust: true, filter })
        .then((dataUrl) => {
          const link = document.createElement('a');
          link.download = `${username}-devdna.png`;
          link.href = dataUrl;
          link.click();
        })
        .catch((err) => {
          console.error('oops, something went wrong!', err);
        });
    }
  };

  const handleTwitterShare = () => {
    if (!data) return;
    const text = `I'm a ${data.type}! ?㎚%0A%0A?꾨왂?? ${data.scores['?꾨왂??]}%0A?쇨??? ${data.scores['?쇨???]}%0A吏묒쨷?? ${data.scores['吏묒쨷 ??컻??]}%0A?쇳뻾?? ${data.scores['?쇳뻾??吏??]}%0A%0ACheck out your DevDNA: http://devdna.site/user/${username}`;
    window.open(`https://twitter.com/intent/tweet?text=${text}`, '_blank');
  };

  const handleCopyLink = () => {
    navigator.clipboard.writeText(`http://devdna.site/user/${username}`);
    alert('Link copied to clipboard!');
  };

  return (
    <div className="app-container">
      {/* 3D Background */}
      <Grass3D data={data} />

      {/* Content Layer */}
      <div className="content-layer">

        <div className="header glow-hover">
          <div className="logo" onClick={() => { navigate('/'); setData(null); setUsername(''); }}>
            <Activity className="logo-icon" size={32} />
            <span>DevDNA</span>
          </div>
        </div>

        <motion.form
          initial={{ y: -50, opacity: 0 }}
          animate={{ y: data ? -200 : 0, opacity: 1 }}
          transition={{ duration: 0.8, ease: "easeOut" }}
          className="search-form"
          onSubmit={handleSearch}
        >
          <div className="input-wrapper">
            <Github className="github-icon" size={24} />
            <input
              type="text"
              className="username-input"
              placeholder="Enter GitHub ID (e.g., luka0116kjh)"
              value={username}
              onChange={(e) => setUsername(e.target.value)}
              disabled={loading}
            />
          </div>
          {!data && (
            <button type="submit" className="btn-primary glow-hover" disabled={loading || !username}>
              Analyze My DNA
            </button>
          )}
        </motion.form>

        {loading && (
          <div className="loader-container">
            <div className="spinner"></div>
            <span className="loading-text">SEQUENCING REPOSITORY DATA...</span>
          </div>
        )}

        {error && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            className="glass-panel"
            style={{ padding: '1rem', color: '#ff3366', marginTop: '1rem', borderColor: '#ff3366' }}
          >
            {error}
          </motion.div>
        )}

        <AnimatePresence>
          {data && !loading && (
            <motion.div
              ref={cardRef}
              initial={{ y: 100, opacity: 0, scale: 0.9 }}
              animate={{ y: 0, opacity: 1, scale: 1 }}
              exit={{ y: 50, opacity: 0 }}
              transition={{ duration: 0.6, type: "spring", bounce: 0.4 }}
              className="result-card glass-panel"
            >
              <div className="user-profile">
                <img src={`https://github.com/${username}.png`} alt={username} className="avatar glow-hover" />
                <div className="user-info">
                  <h2 className="neon-text">{username}</h2>
                  <p>{data.totalContributions} Contributions in the last year</p>
                </div>
              </div>

              <div className="dna-type glow-hover">
                <p>{data.type}</p>
              </div>

              <div className="dna-stats">
                {Object.entries(data.scores).map(([label, score]) => (
                  <div className="stat-row" key={label}>
                    <span className="stat-label">{label}</span>
                    <div className="stat-bar-container">
                      <motion.div
                        initial={{ width: 0 }}
                        animate={{ width: `${score}%` }}
                        transition={{ duration: 1.5, delay: 0.5, ease: "easeOut" }}
                        className="stat-bar"
                      />
                    </div>
                    <span className="stat-value neon-text">{score}</span>
                  </div>
                ))}
              </div>

              {/* These tools won't be in the downloaded image if we hide them or adjust html-to-image filter, but showing them is fine */}
              <div className="actions" data-html2canvas-ignore>
                <button onClick={handleDownload} className="btn-secondary glow-hover" title="Save Image">
                  <Download size={20} /> Image
                </button>
                <button onClick={handleTwitterShare} className="btn-secondary glow-hover" title="Share on Twitter">
                  <Twitter size={20} /> Share
                </button>
                <button onClick={handleCopyLink} className="btn-secondary glow-hover" title="Copy Link">
                  <Share2 size={20} /> Copy
                </button>
              </div>
            </motion.div>
          )}
        </AnimatePresence>

      </div>
    </div>
  );
}

function App() {
  return (
    <Router>
      <Routes>
        <Route path="/" element={<MainApp />} />
        <Route path="/user/:user" element={<MainApp />} />
      </Routes>
    </Router>
  );
}

export default App;
